  'function' => 
  array (
    'name' => 'calendar_month_view',
    'description' => 'Generate an ASCII art calendar for any month/year using Unicode box-drawing characters. Shows days of the week with correct weekday alignment. Composes with date_calculator for date info and text_box_drawing for the frame. Pure function, no side effects.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
